  def icon_css_class(name, default: "w-5 h-5")
    icon = ICONS[name.to_s]
    icon.is_a?(Hash) && icon[:size_class] ? icon[:size_class] : default
  end

  def svg_icon(name, css_class: "w-5 h-5", stroke: "currentColor", fill: "none")
    icon = ICONS[name.to_s]
    return "".html_safe if icon.nil?

    if icon.is_a?(Hash)
      path_data = icon[:paths]
      view_box  = icon[:view_box] || "0 0 24 24"
      svg_fill   = icon[:fill_based] ? stroke : fill
      svg_stroke = icon[:fill_based] ? "none" : stroke
    else
      path_data = icon
      view_box  = "0 0 24 24"
      svg_fill   = fill
      svg_stroke = stroke
    end

    content = <<~SVG
      <svg xmlns="http://www.w3.org/2000/svg" class="#{css_class}" fill="#{svg_fill}" viewBox="#{view_box}" stroke="#{svg_stroke}" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
        #{path_data}
      </svg>
    SVG
    content.html_safe
  end
end
